<?php
namespace App\Http\Controllers\Admin;use App\Http\Controllers\Controller;use App\Models\Category;use Illuminate\Http\{RedirectResponse,Request};use Illuminate\Support\Str;use Illuminate\View\View;
class CategoryController extends Controller{use HandlesAdminUploads;public function index():View{return view('admin.crud.index',['title'=>'مدیریت دسته‌بندی‌ها','items'=>Category::latest()->paginate(15),'route'=>'categories']);}public function create():View{return view('admin.categories.form',['category'=>new Category(['is_active'=>true,'show_in_home'=>true]),'categories'=>Category::all()]);}public function store(Request $r):RedirectResponse{$d=$this->data($r);$d['slug']=$d['slug']?:Str::slug($d['name']);$d['image']=$this->upload($r,'image','categories');Category::create($d);return redirect()->route('admin.categories.index')->with('success','ذخیره شد');}public function edit(Category $category):View{return view('admin.categories.form',compact('category')+['categories'=>Category::where('id','!=',$category->id)->get()]);}public function update(Request $r,Category $category):RedirectResponse{$d=$this->data($r,$category->id);$d['image']=$this->upload($r,'image','categories',$category->image);$category->update($d);return redirect()->route('admin.categories.index')->with('success','به‌روزرسانی شد');}public function destroy(Category $category):RedirectResponse{if($category->products()->exists())return back()->withErrors('این دسته‌بندی دارای محصول است و حذف نمی‌شود.');$category->delete();return back();}private function data(Request $r,$id=null){return $r->validate(['parent_id'=>'nullable|exists:categories,id','name'=>'required','slug'=>'nullable|unique:categories,slug,'.($id??'NULL').',id','image'=>'nullable|image|max:3072','description'=>'nullable','sort_order'=>'nullable|integer','meta_title'=>'nullable','meta_description'=>'nullable'])+['is_active'=>$r->boolean('is_active'),'show_in_home'=>$r->boolean('show_in_home')];}}
